(function(){"use strict";const P=window.OrbArena.PowerRegistry,R=(id,name,description,cooldown,duration,powerBudget,tags,activate,extra={})=>P.register({id,name,category:tags.includes("gravidade")?"gravidade":"elemental",type:"active",rarity:"Épica",description,cooldown,duration,powerBudget,tags,icon:"⊙",activate,...extra});
R("magnetic_cage","Magnetic Cage","Mantém o alvo em órbita curta.",11,5,17,["gravidade","controle"],({world,actor,target,context})=>context.zone(world,actor,target,{kind:"orbit-cage",radius:112,life:5,power:340,color:actor.glowColor}));
R("thermal_conversion","Thermal Conversion","Converte queimadura recebida em aceleração.",9,5,12,["fogo","velocidade"],({actor})=>{if(actor.burn?.timer>0){actor.burn.timer=0;actor.setStatus("haste",5,.42);}else actor.setStatus("haste",2,.22);});
R("gravity_sling","Gravity Sling","Um ponto gravitacional arremessa o usuário.",8,2,14,["gravidade","mobilidade"],({world,actor,target,context})=>{context.zone(world,actor,target,{kind:"gravity",radius:105,life:2,power:430,color:actor.glowColor});context.impulse(actor,target.x-actor.x,target.y-actor.y,390);});
R("blood_beacon","Blood Beacon","Ponto drena vida de quem permanece próximo.",10,7,16,["sustentação","área"],({world,actor,target,context})=>context.zone(world,actor,target,{kind:"blood-beacon",radius:120,life:7,power:3.5,color:"#e84d73",data:{interval:.55}}));
R("pulse_mine","Pulse Mine","Mina estacionária empurra sem dano direto.",7,6,12,["controle","mina"],({world,actor,target,context})=>context.zone(world,actor,target,{kind:"pulse-mine",radius:82,life:6,power:420,color:actor.glowColor,data:{interval:1.2}}));
R("vacuum_trail","Vacuum Trail","Rastro puxa inimigos e projéteis leves.",9,6,14,["gravidade","rastro"],({actor})=>actor.characterState.data.vacuumTrail=6,{update:({world,actor,target,dt,context})=>{actor.characterState.data.vacuumTrail=Math.max(0,(actor.characterState.data.vacuumTrail||0)-dt);if(actor.characterState.data.vacuumTrail>0&&Math.floor(world.time*8)!==Math.floor((world.time-dt)*8))context.zone(world,actor,actor,{kind:"vacuum",at:"self",radius:62,life:2,power:150,color:actor.secondaryColor});}});
R("static_prison","Static Prison","Círculo elétrico pune travessias.",10,6,15,["elemental","controle"],({world,actor,target,context})=>context.zone(world,actor,target,{kind:"static-prison",radius:118,life:6,power:5,color:"#72eaff",data:{interval:.45}}));
R("adaptive_barrier","Adaptive Barrier","Escudo aprende o último tipo de dano.",11,7,16,["defesa","elemental"],({actor,context})=>{context.shield(actor,42);actor.characterState.data.adaptiveBarrier=7;},{onReceive:({actor,event})=>{actor.lastDamageType=event.source||"physical";if(actor.characterState.data.adaptiveBarrier>0)actor.damageReduction=Math.max(actor.damageReduction,.24);}});
R("mass_inversion","Mass Inversion","Troca temporariamente as massas dos duelistas.",10,5,14,["gravidade","massa"],({world,actor,target,context})=>{const a=actor.mass,b=target.mass;actor.mass=b;target.mass=a;context.schedule(world,5,()=>{actor.mass=actor.baseMass;target.mass=target.baseMass;});});
R("gravity_pulse","Gravity Pulse","Alterna puxão e repulsão em pulsos.",11,6,17,["gravidade","área"],({world,actor,target,context})=>{for(let i=0;i<6;i++)context.schedule(world,i*.7,()=>context.zone(world,actor,target,{kind:i%2?"repulse":"gravity",radius:145,life:.55,power:360,color:actor.glowColor}));});
}());
